// ============================================================
// SCOUT v5 — ROUTE + BUILD TASK
// Changes from v4:
//   - Week A rotation now includes dedicated SBIR.gov scan (Thursdays)
//   - NSF Seed Fund (seedfund.nsf.gov) added to Week A (Wednesdays)
//   - Four new sweep keys: sbir_gov_uas, sbir_gov_monk, nsf_seedfund, sbir_sttr_full
//   - WhatsApp sweep commands: Scout sbir_gov_uas, Scout nsf_seedfund, etc.
// ============================================================

const raw = $input.first().json;
const body = raw.body || raw;
const isScheduled = !body.query && !body.command;
const query = String(body.query || body.command || '');

const today = new Date();
const day = today.getDay(); // 0=Sun, 1=Mon, 2=Tue, 3=Wed, 4=Thu, 5=Fri

// ============================================================
// WEEK A vs WEEK B ROTATION
// Odd ISO weeks = Week A (grant-heavy), Even ISO weeks = Week B (BD-heavy)
// ============================================================
const startOfYear = new Date(today.getFullYear(), 0, 1);
const weekNum = Math.ceil(((today - startOfYear) / 86400000 + startOfYear.getDay() + 1) / 7);
const isWeekA = weekNum % 2 !== 0;

// ============================================================
// WEEK A — MARYLAND STATE + FEDERAL GRANTS
// ============================================================
const weekA = {
  1: { // Monday — Lighthouse + EARN
    mode: 'grant',
    query: 'Maryland Lighthouse Industries Upskilling Reskilling Program 2026 workforce grant nonprofit aerospace defense IT manufacturing site:dllr.state.md.us OR site:governor.maryland.gov OR site:commerce.maryland.gov',
    grantName: 'MD_Lighthouse_Upskilling_2026.txt',
    source: 'Maryland DLLR — Lighthouse Sectors'
  },
  2: { // Tuesday — TEDCO
    mode: 'grant',
    query: 'TEDCO Maryland technology development corporation grant 2026 autonomous drone UAS cybersecurity defense startup SBIR matching funds site:tedco.md OR tedco.md',
    grantName: 'TEDCO_2026.txt',
    source: 'TEDCO Maryland'
  },
  3: { // Wednesday — NSF Seed Fund (seedfund.nsf.gov) + Build Our Future
    mode: 'grant',
    query: 'NSF America Seed Fund SBIR STTR 2026 autonomous systems drone UAS cybersecurity hardware trust mission authorization site:seedfund.nsf.gov OR site:nsf.gov OR Maryland "Build Our Future" grant 2026 autonomous technology cybersecurity site:commerce.maryland.gov',
    grantName: 'NSF_SeedFund_BuildOurFuture_2026.txt',
    source: 'NSF Seed Fund / MD Build Our Future'
  },
  4: { // Thursday — SBIR.gov Direct Scan
    mode: 'grant',
    query: 'SBIR STTR Phase I 2026 open solicitation drone UAS autonomous systems mission authorization cybersecurity hardware DHS DoD Army Navy Air Force DARPA site:sbir.gov OR sbir.gov/solicitations',
    grantName: 'SBIR_DirectScan_2026.txt',
    source: 'SBIR.gov — Direct Solicitation Scan'
  },
  5: { // Friday — FAA workforce + Governor press releases sweep
    mode: 'grant',
    query: 'FAA "Aircraft Pilots Workforce Development" UAS drone operator grant 2026 OR Maryland Governor Moore press release grant technology workforce announcement site:faa.gov OR site:governor.maryland.gov',
    grantName: 'FAA_Workforce_MD_Governor_2026.txt',
    source: 'FAA Workforce / MD Governor Office'
  }
};

// ============================================================
// WEEK B — FEDERAL GRANTS + BD TARGETS BY VERTICAL
// ============================================================
const weekB = {
  1: { // Monday — V1 Infrastructure BD (MDSHA + County DPW)
    mode: 'bd',
    query: 'Maryland State Highway Administration MDSHA bridge inspection vendor registration drone aerial UAS Part 107 2026 OR Anne Arundel County DPW infrastructure inspection contract RFP',
    source: 'V1 Infrastructure — MDSHA + County DPW'
  },
  2: { // Tuesday — V1 Utility + V3 OMB M-26-02 compliance
    mode: 'bd',
    query: 'BGE Baltimore Gas Electric NERC FAC-001 FAC-003 drone transmission inspection vendor 2026 OR OMB M-26-02 federal agency UAS compliance deadline May 2026 drone consulting',
    source: 'V1 Utility BD + V3 OMB Compliance'
  },
  3: { // Wednesday — V2 Warehouse BD
    mode: 'bd',
    query: 'Amazon fulfillment warehouse Baltimore autonomous inventory scanning drone 2026 OR pharmaceutical distribution center Maryland autonomous inventory drone inspection 3PL vendor',
    source: 'V2 Warehouse Autonomous Operations'
  },
  4: { // Thursday — V3 DFR + Public Safety BD
    mode: 'bd',
    query: 'Baltimore City Police drone first responder DFR program 2026 OR Anne Arundel Howard County police drone program vendor RFP OR Port Baltimore PSGP security grant drone',
    source: 'V3 DFR / Public Safety'
  },
  5: { // Friday — V7 MONK SBIR + Private Foundation Grants
    mode: 'grant',
    query: 'SBIR DHS DoD drone autonomous UAS trust cybersecurity hardware 2026 Phase I grant site:sbir.gov OR DroneDeploy Resilient Futures grant 2026 nonprofit OR Northrop Grumman Foundation STEM workforce drone grant',
    grantName: 'SBIR_Private_Foundation_2026.txt',
    source: 'SBIR + Private Foundations'
  }
};

// ============================================================
// SWEEP QUERY BANK
// On-demand: POST { sweep: 'sbir_gov_uas' } or WhatsApp: Scout sbir_gov_uas
// NEW IN v5: sbir_gov_uas, sbir_gov_monk, nsf_seedfund, sbir_sttr_full
// ============================================================
const sweepQueries = {

  // ── NEW v5 SBIR / NSF SWEEPS ──────────────────────────────
  sbir_gov_uas: {
    mode: 'grant',
    query: 'site:sbir.gov 2026 open solicitation UAS unmanned aircraft autonomous drone systems mission authorization BVLOS supply chain hardware cybersecurity Phase I Phase II',
    grantName: 'SBIR_Gov_UAS_Sweep_2026.txt',
    source: 'SBIR.gov — UAS / Autonomous Systems Solicitations'
  },
  sbir_gov_monk: {
    mode: 'grant',
    query: 'site:sbir.gov 2026 trusted autonomous systems hardware cryptographic mission authorization drone UAS DHS Science Technology OR DoD autonomous systems governance cybersecurity BVLOS Phase I',
    grantName: 'SBIR_Gov_MONK_2026.txt',
    source: 'SBIR.gov — MONK Architecture Alignment (DHS S&T / DoD)'
  },
  nsf_seedfund: {
    mode: 'grant',
    query: 'site:seedfund.nsf.gov 2026 SBIR STTR autonomous systems drone UAS cybersecurity hardware trust mission authorization robotics OR NSF America Seed Fund open solicitation 2026 autonomous technology startup Phase I',
    grantName: 'NSF_SeedFund_2026.txt',
    source: 'NSF America\'s Seed Fund — seedfund.nsf.gov'
  },
  sbir_sttr_full: {
    mode: 'grant',
    query: 'SBIR STTR 2026 Phase I open solicitation autonomous drone UAS cybersecurity hardware mission governance supply chain DoD DHS DARPA Army Navy Air Force NASA DOE DOT site:sbir.gov OR site:seedfund.nsf.gov',
    grantName: 'SBIR_STTR_FullSweep_2026.txt',
    source: 'SBIR/STTR — Full Federal Agency Sweep'
  },

  // ── EXISTING v4 SWEEPS (unchanged) ───────────────────────
  grants_gov_uas: {
    mode: 'grant',
    query: 'site:grants.gov UAS unmanned aircraft autonomous drone workforce development 2026 open solicitation',
    grantName: 'GrantsGov_UAS_Sweep.txt',
    source: 'Grants.gov UAS Sweep'
  },
  grants_gov_workforce: {
    mode: 'grant',
    query: 'site:grants.gov workforce development technology training drone aerospace cybersecurity 2026 nonprofit Maryland',
    grantName: 'GrantsGov_Workforce_Sweep.txt',
    source: 'Grants.gov Workforce Sweep'
  },
  md_commerce_press: {
    mode: 'grant',
    query: 'site:commerce.maryland.gov grant announcement 2026 autonomous technology aerospace cybersecurity defense manufacturing',
    grantName: 'MD_Commerce_Press_Sweep.txt',
    source: 'Maryland Commerce Press Releases'
  },
  md_governor_press: {
    mode: 'grant',
    query: 'site:governor.maryland.gov 2026 grant investment technology workforce announcement',
    grantName: 'MD_Governor_Press_Sweep.txt',
    source: 'Maryland Governor Press Releases'
  },
  workforce_dev_board: {
    mode: 'grant',
    query: 'Maryland Governor Workforce Development Board 2026 grant announcement lighthouse sectors AI technology training',
    grantName: 'MD_Workforce_Board_2026.txt',
    source: 'MD Governor Workforce Development Board'
  },
  tedco_deep: {
    mode: 'grant',
    query: 'TEDCO 2026 "Builder Fund" OR "Social Innovation Fund" OR "SBIR Proposal Lab" OR "Maryland Innovation Initiative" grant drone autonomous cybersecurity defense',
    grantName: 'TEDCO_Deep_2026.txt',
    source: 'TEDCO All Programs'
  },
  earn_maryland: {
    mode: 'grant',
    query: 'Maryland EARN workforce development grant 2026 drone technology training nonprofit June deadline',
    grantName: 'EARN_Maryland_2026.txt',
    source: 'Maryland EARN'
  },
  cdbg_baltimore: {
    mode: 'grant',
    query: 'Maryland CDBG Community Development Block Grant Baltimore City 2026 minority nonprofit facility technology',
    grantName: 'CDBG_Baltimore_2026.txt',
    source: 'CDBG Baltimore City'
  },
  lighthouse_internship: {
    mode: 'grant',
    query: 'Maryland Lighthouse Industries AI Internship Program 2026 $150000 employer application rolling basis workforce',
    grantName: 'MD_Lighthouse_Internship_2026.txt',
    source: 'MD Lighthouse Internship Program'
  },
  psgp_port_security: {
    mode: 'grant',
    query: 'FEMA Port Security Grant Program PSGP 2026 $90 million maritime drone aerial surveillance security',
    grantName: 'PSGP_PortSecurity_2026.txt',
    source: 'FEMA PSGP'
  },
  uasi_urban_security: {
    mode: 'grant',
    query: 'FEMA Urban Areas Security Initiative UASI 2026 Baltimore Washington drone detection public safety technology grant',
    grantName: 'UASI_2026.txt',
    source: 'FEMA UASI'
  },
  shsp_state_homeland: {
    mode: 'grant',
    query: 'State Homeland Security Program SHSP 2026 Maryland drone C-UAS technology grant law enforcement',
    grantName: 'SHSP_2026.txt',
    source: 'DHS SHSP'
  },
  fema_cuas: {
    mode: 'grant',
    query: 'FEMA C-UAS SLTT counter drone Homeland Security Grant Program 2026 state local tribal territorial $250 million FIFA World Cup security grant site:dhs.gov OR site:fema.gov',
    grantName: 'FEMA_CUAS_SLTT_2026.txt',
    source: 'FEMA / DHS C-UAS'
  },
  dol_wioa: {
    mode: 'grant',
    query: 'DOL WIOA Workforce Innovation Opportunity Act 2026 technology training drone aerospace cybersecurity Maryland nonprofit',
    grantName: 'DOL_WIOA_2026.txt',
    source: 'DOL WIOA'
  },
  nsf_ate: {
    mode: 'grant',
    query: 'NSF Advanced Technological Education ATE grant 2026 drone UAS autonomous technology community college workforce',
    grantName: 'NSF_ATE_2026.txt',
    source: 'NSF ATE Program'
  },
  drone_deploy_foundation: {
    mode: 'grant',
    query: 'DroneDeploy Resilient Futures Technology Grant Program 2026 nonprofit $10000 $20000 reality capture',
    grantName: 'DroneDeploy_Foundation_2026.txt',
    source: 'DroneDeploy Foundation'
  },
  private_foundations: {
    mode: 'grant',
    query: 'Motorola Solutions Foundation technology engineering public safety grant 2026 OR Honda USA Foundation STEM workforce grant drone OR T-Mobile Hometown Grant community technology 2026',
    grantName: 'Private_Foundations_2026.txt',
    source: 'Private Foundations'
  },
  mbe_certification: {
    mode: 'bd',
    query: 'Maryland Minority Business Enterprise MBE certification drone UAS 2026 MDOT GOMA vendor contracts state',
    source: 'MBE / State Vendor Registration'
  },
  v4_entertainment_shows: {
    mode: 'bd',
    query: 'FIFA World Cup 2026 Baltimore Maryland venue security drone show entertainment FEMA grant OR Maryland entertainment drone show permit FAA Part 107 waiver swarm choreography',
    source: 'V4 Entertainment / Shows'
  },
  v5_bvlos_logistics: {
    mode: 'bd',
    query: 'FAA BVLOS drone delivery Maryland 2026 Part 108 pilot program site:faa.gov OR Maryland drone delivery VLOS logistics vendor contract',
    source: 'V5 BVLOS Logistics'
  },
  v6_daas_fleet: {
    mode: 'bd',
    query: 'Drone as a Service DaaS Maryland 2026 fleet leasing government contract OR confined space inspection drone autonomous Maryland utility industrial',
    source: 'V6 DaaS / Fleet Services'
  },
  v7_monk_licensing: {
    mode: 'bd',
    query: 'MONK drone mission authorization hardware trust OEM licensing autonomous UAS BVLOS compliance 2026 OR DoD drone supply chain trusted hardware certification',
    source: 'V7 MONK Technology Licensing'
  },
  cako_partnerships: {
    mode: 'bd',
    query: 'Maryland community college drone workforce training partnership 2026 OR Maryland workforce pipeline employer agreement drone operator Part 107 certification program',
    source: 'CAKO Employer Partnerships'
  },
  johns_hopkins_meia: {
    mode: 'bd',
    query: 'Johns Hopkins medical campus drone delivery logistics 2026 OR MEIA Maryland Economic Innovation Award autonomous technology drone submission',
    source: 'Johns Hopkins / MEIA'
  },
  crown_castle_telecom: {
    mode: 'bd',
    query: 'Crown Castle tower inspection drone vendor portal 2026 OR American Tower drone aerial inspection vendor registration Maryland',
    source: 'V1 Telecom Tower Inspection'
  },
  insurance_surge: {
    mode: 'bd',
    query: 'State Farm Allstate Travelers CBRE JLL drone aerial inspection Maryland property insurance claim 2026 vendor',
    source: 'V1 Insurance / CBRE / JLL'
  }
};

let mode, resolvedQuery, grantName, sourceLabel;

if (isScheduled) {
  const schedule = isWeekA ? weekA : weekB;
  const target = schedule[day] || weekA[1];
  mode = target.mode;
  resolvedQuery = target.query;
  grantName = target.grantName || null;
  sourceLabel = target.source || 'Scheduled';
} else if (body.sweep && sweepQueries[body.sweep]) {
  // On-demand sweep: POST { sweep: 'sbir_gov_uas' }
  const sq = sweepQueries[body.sweep];
  mode = sq.mode;
  resolvedQuery = sq.query;
  grantName = sq.grantName || null;
  sourceLabel = sq.source || body.sweep;
} else {
  // Manual query passthrough
  mode = body.mode || 'bd';
  resolvedQuery = query || 'Maryland drone infrastructure inspection contracts 2026';
  grantName = body.grantName || null;
  sourceLabel = 'Manual';
}

return [{ json: { mode, query: resolvedQuery, grantName, sourceLabel, isScheduled, timestamp: new Date().toISOString() } }];

const fs = require('fs'), https = require('https');
let ctx = {};
try { ctx = JSON.parse(fs.readFileSync('/data/KAI_Context.json', 'utf8')); } catch(e) { ctx = {}; }

const { mode, query, grantName, sourceLabel, isScheduled, timestamp } = $input.first().json;
const founder = ctx.founder || {};
const verticals = ctx.verticals || {};
const entities = ctx.entities || {};
const naics = ctx.naics || {};
const deadlines = ctx.deadlines || [];
const revenue = ctx.revenue_targets || {};
const tech = ctx.technology || {};

const verticalList = Object.entries(verticals).map(([k,v]) =>
  `${k}: ${v.name} | Pricing: ${v.pricing || v.revenue_projection || 'TBD'} | Margin: ${v.margin || 'TBD'}`
).join('\n');

const eafProfile = `EAF: ${entities.EAF?.name} | EIN: ${entities.EAF?.ein} | Type: ${entities.EAF?.type} | Status: ${entities.EAF?.status}`;
const fpProfile  = `FP:  ${entities.FP?.name}  | EIN: ${entities.FP?.ein} | Status: ${entities.FP?.status}`;
const monkProfile = `MONK: ${entities.MONK?.name} | Role: ${entities.MONK?.role} | Status: ${entities.MONK?.status}`;

const techSummary = [
  `MONK: ${tech.MONK?.description || ''} Status: ${tech.MONK?.status || ''} SBIR Target: ${tech.MONK?.sbir_target || ''}`,
  `AKMS: ${tech.AKMS?.description || ''}`,
  `CAKO: ${tech.CAKO?.description || ''} Cohort 1: ${tech.CAKO?.cohort_1_target || ''}`
].join('\n');

const credStack = (founder.credentials || []).join(', ');
const complianceRules = (ctx.compliance_rules || []).join(' | ');

// Pull active deadlines for context (skip FILED/COMPLETE)
const isValidDate = s => /^\d{4}-\d{2}-\d{2}$/.test(s);
const activeDeadlines = deadlines
  .filter(d => d && d.date && isValidDate(d.date) && !['FILED','COMPLETE'].includes((d.status||'').toUpperCase()))
  .map(d => `${d.item} — ${d.date} [${d.entity}]`)
  .join('\n');

let systemMessage, userMessage, outputFolder, outputPrefix;

if (mode === 'grant') {

  systemMessage = `You are Scout, Grant Intelligence Agent for KAI-Netics.\n\nENTITY PROFILES:\n${eafProfile}\n${fpProfile}\n${monkProfile}\n\nFOUNDER: ${founder.name} — ${credStack}\nBACKGROUND: ${founder.background}\n\nTECHNOLOGY ASSETS:\n${techSummary}\n\nSEVEN VERTICALS:\n${verticalList}\n\nSERVICE GEOGRAPHY: Maryland (all 24 counties, priority: Baltimore City, Anne Arundel, Howard, Baltimore County, PG County, Montgomery County), DC Metro, Northern Virginia\n\nNAICS REGISTERED: ${(naics.registered||[]).map(n=>n.code+' '+n.description).join(', ')}\nNAICS RECOMMENDED: ${(naics.recommended||[]).map(n=>n.code+' '+n.description).join(', ')}\n\nACTIVE DEADLINES:\n${activeDeadlines}\n\nREVENUE TARGETS: Y1 ${revenue.year1_total} | Y2 ${revenue.year2_total} | Y3 ${revenue.year3_total}\n\nCOMPLIANCE RULES: ${complianceRules}\n\nSOURCE CONTEXT: ${sourceLabel}\n\nFor SBIR/STTR opportunities specifically: MONK LLC is the SBIR applicant for DoD/DHS. FP (Kevin Alexander International LLC) can also apply. EAF cannot apply for SBIR directly. The MONK SBIR target is DHS S&T or DoD ~$175,000 Phase I. Dr. Alexander Kott (former Chief Scientist, U.S. Army Research Laboratory) is technical advisor — reference his background in proposals.\n\nYour job: Research this grant opportunity and produce a complete grant intelligence file. Be precise — real solicitation numbers, real portal URLs, real deadlines, real award amounts. For SBIR: include the exact solicitation number, topic number, agency, open/close dates, and whether a pre-application or company registration (SAM.gov, SBIR.gov registration) is required first.\n\nFORMAT YOUR OUTPUT EXACTLY AS FOLLOWS:\n\nFUNDER: [exact legal name]\nPROGRAM: [exact program name and solicitation number if SBIR]\nDEADLINE: [specific date or TBD — never guess]\nAWARD RANGE: [dollar amounts — Phase I vs Phase II if SBIR]\nPORTAL / CONTACT: [exact URL — for SBIR use sbir.gov/solicitations or seedfund.nsf.gov]\nELIGIBILITY: [entity type, size, geography, match requirements]\nEAF FIT SCORE: [0–100%]\nFP FIT SCORE: [0–100%]\nFIT RATIONALE: [2–3 sentences tying to KAI-Netics specifics — reference MONK architecture and Dr. Kott for SBIR]\n\nTOP 3 ALIGNMENT POINTS:\n1.\n2.\n3.\n\nTOP 2 RISKS:\n1.\n2.\n\nPREREQUISITES: [SAM.gov UEI required? SBIR.gov account? Company registration? Flag any gaps]\nCOMPETING APPLICANTS: [competitive landscape]\nRECOMMENDED ACTION: [APPLY IMMEDIATELY / APPLY / WATCH / PASS]\nNEXT STEP: [single most important action with URL or contact]\n\nLOI DRAFT OR SBIR ABSTRACT:\n[For grants: 300–400 word LOI. For SBIR: 250-word technical abstract referencing MONK architecture, Dr. Kott ARL advisory, and Part 108 BVLOS regulatory tailwind. Ready for Atlas to expand into full proposal.]`;

  userMessage = `Research this grant/SBIR opportunity thoroughly for KAI-Netics:\n\n${query}\n\nToday is ${new Date().toLocaleDateString('en-US', {timeZone: 'America/New_York'})}.\n\nPriority: Focus on open solicitations or those opening within 90 days. For SBIR.gov scans, list ALL relevant open topics — do not limit to one. For seedfund.nsf.gov, check current open solicitation windows. Flag SAM.gov registration requirement — KAI-Netics does not yet have UEI/CAGE code (critical prerequisite for all federal grants).`;

  outputFolder = 'Maryland_Grants';
  outputPrefix = grantName ? grantName.replace('.txt','') : 'Grant_Intel_' + new Date().toISOString().slice(0,10);

} else {

  systemMessage = `You are Scout, Business Development Research Agent for KAI-Netics.\n\nENTITY PROFILES:\n${fpProfile}\n${eafProfile}\n${monkProfile}\n\nFOUNDER: ${founder.name} — ${credStack}\nBACKGROUND: ${founder.background}\n\nKEVIN'S TWO ROLES ONLY: (1) Sales & BD — closing contracts; (2) MONK technology development. EAF graduates deliver all operational drone services.\n\nSEVEN VERTICALS:\n${verticalList}\n\nTECHNOLOGY ASSETS:\n${techSummary}\n\nTARGET GEOGRAPHY: Baltimore City, Anne Arundel, Howard, Baltimore County, PG County, Montgomery County, DC Metro, Northern Virginia\n\nTARGET CUSTOMER UNIVERSE BY VERTICAL:\nV1 Infrastructure: All 24 MD county DPW offices, MDSHA (2,500+ bridges), DC DDOT (245 bridges), BGE, Pepco, SMECO, Dominion VA, Crown Castle, SBA Communications, CSX, Amtrak NEC, WMATA, State Farm, Allstate, Travelers, CBRE, JLL, MD DNR, Army Corps of Engineers\nV2 Warehouse: Pharmaceutical/medical distributors, cold-chain/food & beverage, 3PL operators, automotive parts, e-commerce fulfillment (Amazon BWI2, Home Depot White Marsh, Target Upper Marlboro)\nV3 Public Safety/DFR: Baltimore City PD, Baltimore City Fire, Anne Arundel PD, Howard County PD, Cecil County Sheriff, Port of Baltimore (PSGP), FIFA World Cup MD venues (FEMA grant buyer), TSA, CBP\nV4 Entertainment: Event promoters, county fair authorities, sports venues, corporate event companies, FIFA World Cup host city coordination\nV5 Logistics/Delivery: Healthcare systems (Johns Hopkins, MedStar, UMMC), pharmaceutical distributors, airport logistics, USPS pilot programs\nV6 DaaS/Fleet: Industrial facilities, confined space operators, digital twin buyers, utility corridor monitoring\nV7 MONK/AKMS/CAKO: OEM drone manufacturers, DoD prime contractors, BVLOS applicants, community colleges, MD workforce pipelines\n\nNAICS REGISTERED: ${(naics.registered||[]).map(n=>n.code+' '+n.description).join(', ')}\nKEY COMPLIANCE HOOKS: FHWA 23 CFR 650, PHMSA 49 CFR 192, OMB M-26-02 (May 20 2026), NDAA fleet cert, NERC FAC-001/003, FAA Part 107, CISSP framework\n\nSOURCE CONTEXT: ${sourceLabel}\n\nFor each BD target produce ALL 8 sections:\n1. TARGET ORG — full name, named decision maker with exact title\n2. PROCUREMENT PORTAL — exact URL\n3. CONTRACT VEHICLE — PSA, blanket PO, state contract, cooperative, sole source, GSA schedule\n4. FIT SCORE 0–100% — with specific rationale\n5. CAPABILITY STATEMENT — 2–3 tight paragraphs Kevin can send today; lead with CISSP + PMP + Part 107\n6. CERTIFICATIONS NEEDED — exact gaps (MBE, SBR, 8(a), NDAA, MDOT, NERC CIP, SAM.gov UEI)\n7. NEXT ACTION — name, phone, email, URL\n8. FOLLOW-UP SEQUENCE — 3-touch outreach plan with dates\n\nToday is ${new Date().toLocaleDateString('en-US', {timeZone: 'America/New_York'})}.`;

  userMessage = `Research this BD target for KAI-Netics immediate outreach:\n\n${query}\n\nProduce all 8 sections. Flag any compliance deadlines creating urgency.`;

  outputFolder = 'Aidan_Outputs/Scout';
  outputPrefix = 'Scout_BD_' + new Date().toISOString().slice(0,10).replace(/-/g,'');
}

const requestBody = JSON.stringify({
  model: 'claude-sonnet-4-20250514',
  max_tokens: 4096,
  system: systemMessage,
  messages: [{ role: 'user', content: userMessage }]
});

const options = {
  hostname: 'api.anthropic.com',
  port: 443,
  path: '/v1/messages',
  method: 'POST',
  headers: {
    'Content-Type': 'application/json',
    'x-api-key': 'REPLACE_WITH_KEY',
    'anthropic-version': '2023-06-01',
    'Content-Length': Buffer.byteLength(requestBody)
  }
};

const result = await new Promise((resolve, reject) => {
  const req = https.request(options, (res) => {
    let d = '';
    res.on('data', c => d += c);
    res.on('end', () => resolve({ status: res.statusCode, body: d }));
  });
  req.on('error', reject);
  req.write(requestBody);
  req.end();
});

let aiOutput = '';
try {
  aiOutput = JSON.parse(result.body).content?.[0]?.text || 'No response from Claude.';
} catch(e) {
  aiOutput = result.body.substring(0, 500);
}

const dateStr = new Date().toISOString().replace(/[:.]/g,'-');
const filename = mode === 'grant'
  ? `${outputPrefix}.txt`
  : `${outputPrefix}_${dateStr}.txt`;
const folderPath = `/data/${outputFolder}`;
fs.mkdirSync(folderPath, { recursive: true });

const header = [
  `SCOUT v5 — KAI-NETICS`,
  `Mode: ${mode.toUpperCase()}`,
  `Source: ${sourceLabel}`,
  `Query: ${query}`,
  `Generated: ${timestamp}`,
  `Scheduled: ${isScheduled}`,
  ``,
  ``
].join('\n');

fs.writeFileSync(`${folderPath}/${filename}`, header + aiOutput + '\n', 'utf8');

const fitMatch  = aiOutput.match(/(?:EAF FIT SCORE|FP FIT SCORE|FIT SCORE)[:\s*\*]*\s*\*?\*?(\d+)/i);
const fitScore  = fitMatch ? fitMatch[1] + '%' : 'See report';
const actionMatch = aiOutput.match(/RECOMMENDED ACTION[:\s*\*]*\s*\*?\*?([^\n]+)/i);
const action    = actionMatch ? actionMatch[1].trim().replace(/\*/g,'') : 'Review report';
const nextMatch = aiOutput.match(/NEXT (?:STEP|ACTION)[:\s*\*]*\s*\*?\*?([^\n]+)/i);
const nextStep  = nextMatch ? nextMatch[1].trim().replace(/\*/g,'').substring(0,100) : 'See report';

const modeLabel = mode === 'grant' ? 'GRANT INTEL' : 'BD REPORT';
const summary = [
  `SCOUT v5 ${modeLabel} — ${sourceLabel}`,
  `Mode: ${mode.toUpperCase()} | Fit: ${fitScore} | Action: ${action}`,
  `Next: ${nextStep}`,
  `Saved: /data/${outputFolder}/${filename}`
].join('\n');

return [{ json: { aiOutput, summary, savedTo: `${folderPath}/${filename}`, query, fitScore, action, mode, filename, outputFolder, isScheduled, sourceLabel, timestamp } }];

const http = require('http');
